const LANE_COLORS   = ['#e8002d','#1a8fff','#00cc55','#ff8800'];
const LANE_COLORS_A = ['rgba(232,0,45,0.14)','rgba(26,143,255,0.14)','rgba(0,204,85,0.14)','rgba(255,136,0,0.14)'];
let currentCategory = 'ALL';
// ═══════════════════════════════════
// KEY CONFIG — persistent via localStorage
// ═══════════════════════════════════
const DEFAULT_KEYS = {
  lane0: ['a', 'ArrowLeft'],
  lane1: ['s', 'ArrowDown'],
  lane2: ['d', 'ArrowRight'],
  lane3: ['w', 'ArrowUp'],
};


const DEFAULT_SPEEDS = {
  easy: 260,
  normal: 340,
  hard: 420
};

function loadSpeed() {
  try {
    return JSON.parse(localStorage.getItem('santes_speed') || 'null') || DEFAULT_SPEEDS;
  } catch (e) {
    return DEFAULT_SPEEDS;
  }
}

function saveSpeed(cfg) {
  try {
    localStorage.setItem('santes_speed', JSON.stringify(cfg));
  } catch (e) {}
}

let SPEEDS = loadSpeed();

function loadKeyConfig() {
  try {
    const saved = JSON.parse(localStorage.getItem('santes_keys') || 'null');
    if (saved && saved.lane0 && saved.lane1 && saved.lane2 && saved.lane3) return saved;
  } catch(e) {}
  return JSON.parse(JSON.stringify(DEFAULT_KEYS));
}

function saveKeyConfig(cfg) {
  try { localStorage.setItem('santes_keys', JSON.stringify(cfg)); } catch(e) {}
}

let keyConfig = loadKeyConfig();

// Build dynamic KEY_MAP from keyConfig
function buildKeyMap() {
  const map = {};
  for (let lane = 0; lane < 4; lane++) {
    const keys = keyConfig['lane' + lane];
    if (Array.isArray(keys)) {
      keys.forEach(k => { if (k) map[k] = lane; });
    }
  }
  return map;
}
let KEY_MAP = buildKeyMap();

// ═══════════════════════════════════
// PROGRESS
// ═══════════════════════════════════
let _memProgress = {};
function getProgress() {
  try { return JSON.parse(localStorage.getItem('santes_progress') || '{}'); } catch(e) { return _memProgress; }
}
function saveProgress(data) {
  _memProgress = data;
  try { localStorage.setItem('santes_progress', JSON.stringify(data)); } catch(e) {}
}

function getSongData(id) {
  const p = getProgress();
  return p[id] || { stars: 0, bestScore: 0, exUnlocked: false };
}
function setSongData(id, data) {
  const p = getProgress();
  p[id] = { ...getSongData(id), ...data };
  saveProgress(p);
}

// ═══════════════════════════════════
// SCREENS
// ═══════════════════════════════════
function showScreen(id) {
  document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));
  document.getElementById('screen-' + id).classList.add('active');
}

// ═══════════════════════════════════
// TITLE SCREEN — PARTICLES + CONFETTI
// ═══════════════════════════════════
(function initParticles() {
  const c = document.getElementById('title-particles');
  const ctx = c.getContext('2d');
  let W, H, pts = [], confetti = [];
  const CONFETTI_COLORS = ['#c8a84b','#e8002d','#1a3a6e','#006633','#fff','#ff8800'];

  function resize() {
    W = c.width  = c.offsetWidth  || 680;
    H = c.height = c.offsetHeight || 620;
    pts = Array.from({length: 50}, () => ({
      x: Math.random()*W, y: Math.random()*H,
      vx: (Math.random()-0.5)*0.35, vy: (Math.random()-0.5)*0.35,
      r: Math.random()*1.5+0.5, a: Math.random()*0.6+0.1
    }));
    confetti = Array.from({length: 35}, () => ({
      x: Math.random()*W, y: Math.random()*H - H,
      vx: (Math.random()-0.5)*1.2, vy: Math.random()*1.8+0.8,
      rot: Math.random()*360, drot: (Math.random()-0.5)*4,
      col: CONFETTI_COLORS[Math.floor(Math.random()*CONFETTI_COLORS.length)],
      w: 5 + Math.random()*8, h: 3 + Math.random()*5
    }));
  }
  resize();
  window.addEventListener('resize', resize);

  function frame() {
    ctx.clearRect(0, 0, W, H);
    for (const p of pts) {
      p.x += p.vx; p.y += p.vy;
      if (p.x < 0 || p.x > W) p.vx *= -1;
      if (p.y < 0 || p.y > H) p.vy *= -1;
      ctx.beginPath(); ctx.arc(p.x, p.y, p.r, 0, Math.PI*2);
      ctx.fillStyle = `rgba(200,168,75,${p.a})`; ctx.fill();
    }
    for (const piece of confetti) {
      piece.x += piece.vx; piece.y += piece.vy; piece.rot += piece.drot;
      if (piece.y > H + 20) { piece.y = -20; piece.x = Math.random() * W; }
      ctx.save(); ctx.translate(piece.x, piece.y); ctx.rotate(piece.rot * Math.PI / 180);
      ctx.fillStyle = piece.col + 'bb';
      ctx.fillRect(-piece.w/2, -piece.h/2, piece.w, piece.h); ctx.restore();
    }
    requestAnimationFrame(frame);
  }
  frame();
})();

// ═══════════════════════════════════
// CONFIG SCREEN — KEY BINDING
// ═══════════════════════════════════
const LANE_LABELS = ['← (Esquerra)', '↓ (Centre)', '→ (Centre)', '↑ (Dreta)'];
let listeningLane = null;
let listeningSlot = null; // 0 or 1 (primary / secondary)

function buildConfigScreen() {
  const container = document.getElementById('config-keys-container');
  container.innerHTML = '';
  for (let lane = 0; lane < 4; lane++) {
    const keys = keyConfig['lane' + lane];
    const row = document.createElement('div');
    row.className = 'config-row';
    row.style.borderLeft = `3px solid ${LANE_COLORS[lane]}`;

    const label = document.createElement('div');
    label.className = 'config-lane-label';
    label.textContent = LANE_LABELS[lane];

    const keysDiv = document.createElement('div');
    keysDiv.className = 'config-keys';

    for (let slot = 0; slot < 2; slot++) {
      const btn = document.createElement('button');
      btn.className = 'config-key-btn';
      btn.id = `cfg-btn-${lane}-${slot}`;
      btn.textContent = formatKeyLabel(keys[slot] || '—');
      btn.addEventListener('click', () => startListening(lane, slot));
      keysDiv.appendChild(btn);
    }

    row.appendChild(label);
    row.appendChild(keysDiv);
    container.appendChild(row);
  }
  updateConfigLaneBar();
}

function formatKeyLabel(key) {
  if (!key) return '—';
  const map = {
    'ArrowLeft': '← Fletxa', 'ArrowRight': '→ Fletxa',
    'ArrowUp': '↑ Fletxa', 'ArrowDown': '↓ Fletxa',
    ' ': 'Espai'
  };
  return map[key] || key.toUpperCase();
}

function updateConfigLaneBar() {
  for (let lane = 0; lane < 4; lane++) {
    const el = document.getElementById(`cfg-lane-label-${lane}`);
    if (el) {
      const keys = keyConfig['lane' + lane];
      const parts = keys.filter(Boolean).map(k => formatKeyLabel(k));
      el.textContent = parts.join(' / ');
    }
  }
}

function startListening(lane, slot) {
  if (listeningLane !== null) {
    // cancel previous
    const prevBtn = document.getElementById(`cfg-btn-${listeningLane}-${listeningSlot}`);
    if (prevBtn) { prevBtn.classList.remove('listening'); prevBtn.textContent = formatKeyLabel(keyConfig['lane'+listeningLane][listeningSlot] || '—'); }
  }
  listeningLane = lane;
  listeningSlot = slot;
  const btn = document.getElementById(`cfg-btn-${lane}-${slot}`);
  btn.classList.add('listening');
  btn.textContent = '...';
}

function handleConfigKey(e) {
  if (listeningLane === null) return;
  e.preventDefault();
  e.stopPropagation();

  const key = e.key;
  // Escape cancels
  if (key === 'Escape') {
    const btn = document.getElementById(`cfg-btn-${listeningLane}-${listeningSlot}`);
    if (btn) { btn.classList.remove('listening'); btn.textContent = formatKeyLabel(keyConfig['lane'+listeningLane][listeningSlot] || '—'); }
    listeningLane = null; listeningSlot = null;
    return;
  }

  // Remove this key from any other lane/slot to avoid conflicts
  for (let l = 0; l < 4; l++) {
    keyConfig['lane' + l] = keyConfig['lane' + l].map(k => (k === key && !(l === listeningLane && keyConfig['lane'+l].indexOf(k) === listeningSlot)) ? '' : k);
  }

  keyConfig['lane' + listeningLane][listeningSlot] = key;
  saveKeyConfig(keyConfig);
  KEY_MAP = buildKeyMap();

  const btn = document.getElementById(`cfg-btn-${listeningLane}-${listeningSlot}`);
  if (btn) { btn.classList.remove('listening'); btn.textContent = formatKeyLabel(key); }

  // Refresh all buttons to reflect cleared conflicts
  buildConfigScreen();
  listeningLane = null; listeningSlot = null;
}

document.addEventListener('keydown', e => {
  if (document.getElementById('screen-config').classList.contains('active')) {
    handleConfigKey(e);
    return;
  }
  if (keysHeld.has(e.key)) return; keysHeld.add(e.key);
  const lane = KEY_MAP[e.key];
  if (lane !== undefined) { e.preventDefault(); tapLane(lane, null); }
});

// ═══════════════════════════════════
// SONG SELECT
// ═══════════════════════════════════
function buildSongGrid() {
  const grid = document.getElementById('songs-grid');
  grid.innerHTML = '';

  const filteredSongs = SONGS.filter(song => {
    return currentCategory === 'ALL' || song.categoria === currentCategory;
  });

  for (const song of filteredSongs) {
    const sd = getSongData(song.id);
    const card = document.createElement('div');
    card.className = 'song-card';

    const bgDiv = document.createElement('div');
    bgDiv.className = 'song-card-bg';
    bgDiv.style.backgroundImage = `url(${song.bgImage})`;

    const overlay = document.createElement('div'); 
    overlay.className = 'song-card-overlay';

    const info = document.createElement('div'); 
    info.className = 'song-card-info';
    info.innerHTML = `
      <div class="song-card-title">${song.title}</div>
      <div class="song-card-meta">
        ${song.artist} · ${Math.floor(song.duration/60)}:${String(Math.floor(song.duration%60)).padStart(2,'0')}
      </div>
      <div class="song-card-difficulty">
        ${song.dificultad}
      </div>
      <div class="song-card-category">
        ${song.categoria}
      </div>
    `;

    const stars = document.createElement('div'); 
    stars.className = 'song-stars';
    for (let i=1; i<=3; i++) {
      const s = document.createElement('span');
      s.className = 'star ' + (sd.stars >= i ? 'filled' : 'empty');
      s.textContent = '★'; 
      stars.appendChild(s);
    }

    card.appendChild(bgDiv); 
    card.appendChild(overlay); 
    card.appendChild(info); 
    card.appendChild(stars);

    if (sd.exUnlocked) {
      const b = document.createElement('div'); 
      b.className = 'badge-ex'; 
      b.textContent = '2× EX'; 
      card.appendChild(b);
    }

    if (song.locked) {
      const lock = document.createElement('div'); 
      lock.className = 'badge-locked'; 
      lock.textContent = '⚔'; 
      card.appendChild(lock);
    } else {
      card.addEventListener('click', () => {
        if (sd.exUnlocked) {
          openModeSelector(song);
        } else {
          startSong(song, false);
        }
      });
    }

    grid.appendChild(card);
  }
}




function openModeSelector(song) {
  const overlay = document.createElement('div');
  overlay.className = 'mode-overlay';

  overlay.innerHTML = `
    <div class="mode-box">
      <div class="mode-title">${song.title}</div>

      <button class="mode-btn normal">▶ Modo Normal</button>
      <button class="mode-btn ex">⚡ Modo 2× EX</button>

      <button class="mode-cancel">Cancelar</button>
    </div>
  `;

  document.body.appendChild(overlay);

  overlay.querySelector('.normal').onclick = () => {
    overlay.remove();
    startSong(song, false);
  };

  overlay.querySelector('.ex').onclick = () => {
    overlay.remove();
    startSong(song, true);
  };

  overlay.querySelector('.mode-cancel').onclick = () => {
    overlay.remove();
  };
}

// ═══════════════════════════════════
// AUDIO FADE-OUT HELPER
// ═══════════════════════════════════
function stopAudio(aud, fadeMs) {
  if (!aud) return;
  // Handle the fake timer object (no volume property, has pause())
  if (typeof aud.volume === 'undefined') {
    try { aud.pause(); } catch(e) {}
    return;
  }
  // Real HTMLAudioElement — immediate hard stop (most reliable)
  try {
    aud.volume = 0;
    aud.pause();
    aud.currentTime = 0;
  } catch(e) {}
}

// ═══════════════════════════════════
// GAME ENGINE
// ═══════════════════════════════════
let G = {};
const canvas = document.getElementById('game-canvas');
const ctx2   = canvas.getContext('2d');

function resizeCanvas() {
  const area = document.getElementById('canvas-area');
  canvas.width = area.clientWidth; canvas.height = area.clientHeight;
}

function startSong(song, exMode) {
  // --- Clean up any running game first ---
  if (G.animId) { cancelAnimationFrame(G.animId); G.animId = null; }
  if (G.audio) { stopAudio(G.audio, 0); G.audio = null; }
  G.running = false;

  exMode = exMode || false;
  const sd   = getSongData(song.id);
  const isEx = exMode && sd.exUnlocked;

  G = {
  song, isEx,

  loops: 0,
  maxLoops: song.id === 'amigo' ? 2 : 1,

  notes: (isEx ? song.notesHard : song.notesEasy).map(n => ({
    time: n[0], lane: n[1], hit: false, missed: false, _y: -999
  })),

  noteIdx: 0, activeNotes: [],
  score: 0, combo: 0, maxCombo: 0, lives: song.vidas,
  totalNotes: 0, hitCount: 0, perfectCount: 0, greatCount: 0, missCount: 0,
  running: false, audio: null, animId: null, t0: null,
  gameOverPending: false
};
// 🔥 SPEED SEGÚN DIFICULTAD + LOCALSTORAGE
const difficulty = document.getElementById('difficulty')?.value || 'normal';

// si no existe aún, usa fallback seguro
G.speed = SPEEDS?.[difficulty] || 340;

console.log('[START SONG] dificultad:', difficulty, 'speed:', G.speed);
  G.totalNotes = G.notes.length;

  document.getElementById('hud-song-name').textContent = song.title.toUpperCase() + (isEx ? ' · EX' : '');
  document.getElementById('hud-score').textContent     = '0';
  document.getElementById('hud-combo').textContent     = '';
  document.getElementById('hud-lives').textContent = '♥'.repeat(song.vidas);
  document.getElementById('hud-acc').textContent       = '';
  document.getElementById('progress-fill').style.width = '0%';

  // Update lane bar key labels based on current keyConfig
  updateLaneBarLabels();

  // ── VÍDEO DE FONS ──────────────────────────────────────────
  const vid = document.getElementById('game-video-bg');
  if (vid) {
    vid.pause();
    vid.removeAttribute('src');
    vid.load();
    if (song.videoSrc) {
      vid.src = song.videoSrc;
      vid.muted = true;
      vid.loop = true;
      vid.playsInline = true;
      vid.playbackRate = 1.0;
      vid.load();
      vid.play().catch(() => {});
    }
  }

  showScreen('game');
  resizeCanvas();
if (song.audioSrc) {

  const src = isEx && song.audioSrcEx ? song.audioSrcEx : song.audioSrc;

  const aud = new Audio(src);
  aud.preload = 'auto';
  aud.volume = 1.0;

  G.audio = aud;

  // 🔁 CONTROL DE REPETICIÓN MANUAL
  const maxLoops = song.id === 'amigo' ? 1 : 0; // 0 = 1 vez, 1 = 2 veces
  G.loops = 0;

  function playAudio() {
    const p = aud.play();

    if (p) {
      p.catch(err => console.warn('play blocked', err));
    }
  }

  aud.onended = () => {
    G.loops++;

    if (G.loops <= maxLoops && G.running) {
      aud.currentTime = 0;
      playAudio();
    }
  };

  playAudio();

  const startGame = () => {
    G.running = true;
    G.animId = requestAnimationFrame(gameLoop);
  };

  if (aud.readyState >= 2) {
    startGame();
  } else {
    aud.oncanplay = startGame;
  }

} else {
  _startTimer(isEx);
}
}

function updateLaneBarLabels() {
  for (let lane = 0; lane < 4; lane++) {
    const el = document.getElementById('lt' + lane);
    if (!el) continue;
    const kt = el.querySelector('.kt');
    if (!kt) continue;
    const keys = keyConfig['lane' + lane];
    const parts = (keys || []).filter(Boolean).map(k => formatKeyLabel(k));
    kt.textContent = parts.join(' / ');
  }
}

function _startTimer(isEx) {
  G.t0 = performance.now();

  // NO reemplaces G.audio
  G.timerMode = true;

  G.getTime = () => (performance.now()-G.t0)/1000;

  G.running = true;
  G.animId = requestAnimationFrame(gameLoop);
}


function getHitY() { return canvas.height - 40; }
const HIT_ZONE_HALF = window.innerWidth <= 768 ? 75 : 55;

function spawnNotes(t) {
  const hitY = getHitY();
  const speed = G.speed || 340;

  while (G.noteIdx < G.notes.length) {
    const n = G.notes[G.noteIdx];
    if (n.time - hitY / speed <= t) {
      G.activeNotes.push(n);
      G.noteIdx++;
    } else break;
  }
}

function drawGame(t) {
  if (!G || !G.activeNotes) return;

  const W = canvas.width || 800;
  const H = canvas.height || 600;

  const hitY = getHitY();
  const isMobile = window.innerWidth <= 768;
const GAP = isMobile ? 8 : 8;
const LANE_W = (W - GAP * 3) / 4;
const NOTE_H = isMobile ? 180 : 50;
const padding = 0;                 // padding mínim per veure el color de fons

  const speed = Number(G.speed) || 340;

  ctx2.clearRect(0, 0, W, H);

// LANES BACKGROUND — amb offset per gap
for (let i = 0; i < 4; i++) {
  const lx = i * (LANE_W + GAP);
  ctx2.fillStyle = LANE_COLORS_A[i];
  ctx2.fillRect(lx, 0, LANE_W, H);
}

// HIT ZONE
for (let i = 0; i < 4; i++) {
  const lx = i * (LANE_W + GAP);
  ctx2.fillStyle = 'rgba(255,255,255,0.04)';
  roundRect(ctx2, lx + padding, hitY - HIT_ZONE_HALF, LANE_W - padding*2, HIT_ZONE_HALF * 2, 6);
  ctx2.fill();
  ctx2.strokeStyle = 'rgba(200,168,75,0.18)';
  ctx2.lineWidth = 1;
  roundRect(ctx2, lx + padding, hitY - HIT_ZONE_HALF, LANE_W - padding*2, HIT_ZONE_HALF * 2, 6);
  ctx2.stroke();
}

ctx2.fillStyle = 'rgba(200,168,75,0.25)';
ctx2.fillRect(0, hitY - 1, W, 2);

// NOTES
const notes = G.activeNotes;
for (let i = 0; i < notes.length; i++) {
  const n = notes[i];
  if (!n || n.hit || n.missed) continue;
  const lane = n.lane ?? 0;
  const lx = lane * (LANE_W + GAP);
  const nx = lx + padding;
  const nW = LANE_W - padding * 2;
  const y = hitY - (n.time - t) * speed - NOTE_H / 2;
  n._y = y + NOTE_H / 2;
  ctx2.shadowColor = LANE_COLORS[lane];
  ctx2.shadowBlur = 14;
  ctx2.fillStyle = LANE_COLORS[lane];
  roundRect(ctx2, nx, y, nW, NOTE_H, 6);
  ctx2.fill();
  ctx2.shadowBlur = 0;
}
  // ─────────────────────────
  // AUTO MISS (SAFE LOOP)
  // ─────────────────────────
  for (let i = 0; i < notes.length; i++) {
    const n = notes[i];
    if (!n || n.hit || n.missed) continue;

    if (n._y > hitY + HIT_ZONE_HALF + 30) {
      n.missed = true;
      G.missCount = (G.missCount || 0) + 1;
      G.combo = 0;
      G.lives = Math.max(0, (G.lives || 0) - 1);

      updateHUD?.();
      flashLane?.(n.lane, 'miss');

      if (G.lives <= 0 && !G.gameOverPending) {
        G.gameOverPending = true;
        G.running = false;

        if (G.animId) cancelAnimationFrame(G.animId);
        G.animId = null;

        const audRef = G.audio;
        G.audio = null;
        stopAudio?.(audRef, 0);

        const vid = document.getElementById('game-video-bg');
        if (vid) { try { vid.pause(); } catch (e) {} }

        setTimeout(() => endGame?.(), 400);
        return;
      }
    }
  }
}


function roundRect(ctx,x,y,w,h,r) {
  ctx.beginPath(); ctx.moveTo(x+r,y); ctx.lineTo(x+w-r,y);
  ctx.quadraticCurveTo(x+w,y,x+w,y+r); ctx.lineTo(x+w,y+h-r);
  ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h); ctx.lineTo(x+r,y+h);
  ctx.quadraticCurveTo(x,y+h,x,y+h-r); ctx.lineTo(x,y+r);
  ctx.quadraticCurveTo(x,y,x+r,y); ctx.closePath();
}

function gameLoop() {
  if (!G.running) return;
  const t = G.timerMode ? G.getTime() : (G.audio ? G.audio.currentTime : 0);
  if (t >= G.song.duration) {
  if (G.loops < G.maxLoops - 1) {
    G.loops++;

    // reiniciar audio
    if (G.audio) {
      G.audio.currentTime = 0;
      G.audio.play();
    }

    // reiniciar timer si no usas audio
    if (G.timerMode) {
      G.t0 = performance.now();
    }

    return;
  }
}
  spawnNotes(t); drawGame(t);
  if (!G.running) return; // drawGame may have set running=false on game over
  const dur = G.song.duration;
  document.getElementById('progress-fill').style.width = Math.min(t/dur*100,100)+'%';
  // Level complete
  if (G.noteIdx >= G.notes.length && G.activeNotes.every(n => n.hit || n.missed)) {
    G.running = false;
    cancelAnimationFrame(G.animId);
    G.animId = null;
    const audRef = G.audio;
    G.audio = null;
    stopAudio(audRef, 0);
    const vid = document.getElementById('game-video-bg');
    if (vid) { try { vid.pause(); } catch(e) {} }
    setTimeout(() => endGame(), 300);
    return;
  }
  G.animId = requestAnimationFrame(gameLoop);
}

function tapLane(lane, e) {
  if (e) e.preventDefault();
  if (!G.running) return;
  const hitY = getHitY();
  let best = null, bestDist = Infinity;
  for (const n of G.activeNotes) {
    if (n.hit||n.missed||n.lane!==lane) continue;
    const dist = Math.abs(n._y-hitY);
    if (dist < bestDist) { bestDist=dist; best=n; }
  }
  if (best && bestDist <= HIT_ZONE_HALF+20) {
    best.hit=true; G.hitCount++; G.combo++;
    if (G.combo>G.maxCombo) G.maxCombo=G.combo;
    const pts = bestDist<HIT_ZONE_HALF*0.35?300:bestDist<HIT_ZONE_HALF*0.7?200:100;
    if (pts===300) G.perfectCount++; else if (pts>=200) G.greatCount++;
    G.score += pts * Math.min(G.combo,10);
    const label = pts===300?'PERFECT':pts===200?'GREAT':'OK';
    const col   = pts===300?'#f5e0a0':pts===200?'#6ae0ff':'#ffffff';
    showFeedback(lane,label,col); flashLane(lane,'hit'); updateHUD();
  } else { flashLane(lane,'miss'); }
}

function flashLane(lane,type) {
  const el = document.getElementById('lt'+lane);
  el.classList.add(type==='hit'?'hit':'miss-flash');
  setTimeout(()=>el.classList.remove('hit','miss-flash'),130);
}

function showFeedback(lane, text, color) {
  const area = document.getElementById('canvas-area');
  const isMobile = window.innerWidth <= 768;
  const GAP = isMobile ? 4 : 3;
  const LANE_W = (canvas.width - GAP * 3) / 4;
  const lx = lane * (LANE_W + GAP);
  const el = document.createElement('div');
  el.className = 'feedback'; el.style.color = color;
  el.style.left = (lx + LANE_W / 2 - 40) + 'px';
  el.style.top = (getHitY() - 70) + 'px';
  el.textContent = text; area.appendChild(el);
  setTimeout(() => el.remove(), 560);
}

function updateHUD() {
  document.getElementById('hud-score').textContent = G.score.toLocaleString();
  const c = document.getElementById('hud-combo');
  c.textContent = G.combo>1?'×'+G.combo:'';
  c.classList.remove('pop'); void c.offsetWidth; if(G.combo>1) c.classList.add('pop');
  document.getElementById('hud-lives').textContent = '♥'.repeat(Math.max(0, G.lives));
  const acc = G.hitCount>0?Math.round(G.hitCount/(G.hitCount+G.missCount)*100):100;
  document.getElementById('hud-acc').textContent = acc+'%';
}

// ═══════════════════════════════════════════════════════════════
// SUBSTITUEIX la funció endGame() existent al fitxer principal
// ═══════════════════════════════════════════════════════════════

function endGame() {
  G.running = false;
  if (G.animId) { cancelAnimationFrame(G.animId); G.animId = null; }
  if (G.audio)  { stopAudio(G.audio, 0); G.audio = null; }

  const hitPct   = G.totalNotes > 0 ? G.hitCount / G.totalNotes : 0;
  const stars    = hitPct >= 0.95 ? 3 : hitPct >= 0.75 ? 2 : hitPct >= 0.5 ? 1 : 0;
  const sd       = getSongData(G.song.id);
  const unlockEx = !G.isEx && stars === 3 && !sd.exUnlocked;

  setSongData(G.song.id, {
    stars:      Math.max(sd.stars, stars),
    bestScore:  Math.max(sd.bestScore, G.score),
    exUnlocked: sd.exUnlocked || unlockEx,
  });

  // ── Contingut bàsic ──
  document.getElementById('res-song').textContent    = G.song.title.toUpperCase() + (G.isEx ? ' · EX 2×' : '');
  document.getElementById('res-score').textContent   = G.score.toLocaleString();
  document.getElementById('res-perfect').textContent = G.perfectCount;
  document.getElementById('res-great').textContent   = G.greatCount;
  document.getElementById('res-miss').textContent    = G.missCount;

  // ── Estrelles ──
  const starsEl = document.getElementById('res-stars');
  starsEl.textContent = '';
  for (let i = 1; i <= 3; i++) {
    const s = document.createElement('span');
    s.style.color  = stars >= i ? '#c8a84b' : '#2a2a2a';
    s.textContent  = '★';
    starsEl.appendChild(s);
  }

  // ── Banner desbloqueig mode normal ──
  const banner = document.getElementById('unlock-banner');
  if (unlockEx) {
    banner.textContent = '✦ Has desbloquejat el MODE EX 2×!';
    banner.classList.add('show');
  } else {
    banner.classList.remove('show');
  }

  // ── Banner especial MODE EX ──────────────────────────────────
  // Obtenim o creem el banner EX (persisteix entre partides)
  let exBanner = document.getElementById('ex-clear-banner');
  if (!exBanner) {
    exBanner = document.createElement('div');
    exBanner.id = 'ex-clear-banner';

    // Injectem l'estil si no existeix
    if (!document.getElementById('ex-banner-style')) {
      const style = document.createElement('style');
      style.id = 'ex-banner-style';
      style.textContent = `
        #ex-clear-banner {
          display: none;
          margin: 14px auto 0;
          max-width: 360px;
          padding: 14px 20px 12px;
          background: linear-gradient(135deg, rgba(200,168,75,0.12), rgba(255,200,50,0.06));
          border: 1.5px solid rgba(200,168,75,0.55);
          border-radius: 12px;
          text-align: center;
          animation: exBannerIn .45s cubic-bezier(.22,1,.36,1);
        }
        #ex-clear-banner.show { display: block; }
        @keyframes exBannerIn {
          from { opacity:0; transform: scale(.92) translateY(10px); }
          to   { opacity:1; transform: none; }
        }
        #ex-clear-banner .ex-label {
          font-family: 'Cinzel Decorative', 'Cinzel', serif;
          font-size: .72rem;
          letter-spacing: .18em;
          color: #c8a84b;
          text-transform: uppercase;
          margin-bottom: 5px;
        }
        #ex-clear-banner .ex-score-line {
          font-family: 'Titillium Web', sans-serif;
          font-size: 1.45rem;
          font-weight: 700;
          color: #fff;
          letter-spacing: .04em;
          line-height: 1.15;
        }
        #ex-clear-banner .ex-score-line span {
          color: #f5d06a;
        }
        #ex-clear-banner .ex-sub {
          font-family: 'Titillium Web', sans-serif;
          font-size: .78rem;
          color: rgba(255,255,255,0.55);
          margin-top: 5px;
        }
        #ex-clear-banner .ex-acc {
          display: inline-block;
          margin-top: 8px;
          padding: 3px 12px;
          background: rgba(200,168,75,0.15);
          border: 1px solid rgba(200,168,75,0.3);
          border-radius: 20px;
          font-family: 'Titillium Web', sans-serif;
          font-size: .8rem;
          color: #c8a84b;
          letter-spacing: .06em;
        }
        /* Estrella EX daurada animada */
        #ex-clear-banner .ex-stars {
          font-size: 1.1rem;
          margin-bottom: 4px;
          animation: exStarsPulse 1.8s ease-in-out infinite;
        }
        @keyframes exStarsPulse {
          0%,100% { text-shadow: 0 0 8px rgba(200,168,75,0.4); }
          50%      { text-shadow: 0 0 20px rgba(200,168,75,0.9); }
        }
      `;
      document.head.appendChild(style);
    }

    // Inserim el banner just sota el banner d'unlock existent
    const unlockBanner = document.getElementById('unlock-banner');
    if (unlockBanner && unlockBanner.parentNode) {
      unlockBanner.parentNode.insertBefore(exBanner, unlockBanner.nextSibling);
    } else {
      // Fallback: afegim a la pantalla de resultat
      const resScreen = document.getElementById('screen-result');
      if (resScreen) resScreen.appendChild(exBanner);
    }
  }

  if (G.isEx) {
    const acc     = G.hitCount > 0 ? Math.round(G.hitCount / (G.hitCount + G.missCount) * 100) : 100;
    const starsStr = '★'.repeat(stars) + '☆'.repeat(3 - stars);
    const isRecord = G.score > (sd.bestScore || 0);

    // Missatge personalitzat segons rendiment
    let headline, sub;
    if (acc === 100) {
      headline = '⚡ FULL COMBO EX!';
      sub      = 'Perfecció absoluta al doble de velocitat. Increïble.';
    } else if (stars === 3) {
      headline = '⚡ EX CLEARED — 3 ESTRELLES!';
      sub      = isRecord ? '🏆 Nova puntuació rècord!' : 'Excel·lent execució en mode EX 2×.';
    } else if (stars >= 1) {
      headline = '⚡ EX COMPLETAT';
      sub      = 'Has superat el mode al doble de velocitat. Bona feina!';
    } else {
      headline = '⚡ MODE EX 2× INTENTAT';
      sub      = 'El doble de velocitat no perdona. Torna-ho a intentar!';
    }

    exBanner.innerHTML = `
      <div class="ex-stars">${starsStr}</div>
      <div class="ex-label">Mode EX · 2× Velocitat</div>
      <div class="ex-score-line">${headline}</div>
      <div class="ex-sub">${sub}</div>
      <div class="ex-acc">Precisió: ${acc}% · ${G.hitCount}/${G.totalNotes} notes</div>
    `;
    exBanner.classList.add('show');
  } else {
    exBanner.classList.remove('show');
  }
  // ─────────────────────────────────────────────────────────────

  // ── Botó de reintent ──
  const retryBtn = document.getElementById('btn-res-retry');
  const newSd    = getSongData(G.song.id);
  if (newSd.exUnlocked && !G.isEx) {
    retryBtn.textContent = 'MODE EX 2× ▶';
    retryBtn.onclick     = () => startSong(G.song, true);
  } else {
    retryBtn.textContent = 'TORNAR A JUGAR';
    retryBtn.onclick     = () => startSong(G.song, G.isEx);
  }

  showScreen('result');
}

